THE CLAIM:
{
 "title": "Colo-based geo weights inflate NL, hide Swiss and German demand",
 "narrative": "The model splits each country's share using colocation data. But 29% of the market is enterprise on-premise, which colocation data does not count. Switzerland's real installed base is about 3x its colo figure, and Germany's load exceeds 2,700 MW versus a 1,737 MW colo figure, while the Dutch weight reflects the Amsterdam colo hub. As a result, country order, channel plans and SAM are wrong for a third of the market.",
 "mechanism": [
  {
   "step": "trigger",
   "text": "All geo weights come from one colocation table that misreports countries.",
   "refs": [
    "digest:geo-region-denominator#c0",
    "digest:geo-region-denominator#c1",
    "digest:geo-region-denominator#c3"
   ]
  },
  {
   "step": "propagation",
   "text": "Colo data excludes the 29% enterprise on-premise market it should weight.",
   "refs": [
    "ledger:seg.enterprise",
    "ledger:geo.CH",
    "ledger:geo.DE"
   ]
  },
  {
   "step": "model-impact",
   "text": "NL is overweighted, Switzerland understated, and 29% of TAM lands in wrong countries.",
   "refs": [
    "ledger:geo.NL",
    "ledger:serviceableFactor"
   ]
  }
 ],
 "falsifier": "A total-installed-load country split for CE-7 that reproduces the colo weights within a few points, with NL near 0.28 and CH near 0.08.",
 "category": "model-structure",
 "evidence": [
  {
   "title": "Status and development of the German data centre landscape – Executive Summary",
   "sourceType": "industry-report",
   "publisher": "BMWK (Federal Ministry for Economic Affairs and Climate Action)",
   "date": "2025-03",
   "excerpt": "With over 2,000 data centres and an installed IT power demand of over 2,700 MW, Germany is already the largest centre for digital infrastructure in Europe.",
   "url": "https://www.bundeswirtschaftsministerium.de/Redaktion/EN/Publikationen/Digitale-Welt/status-and-development-of-the-german-data-centre-landscape-executive-summary.pdf?__blob=publicationFile&v=2",
   "attached": true
  },
  {
   "title": "CBRE Suisse: latest Swiss data centre market figures",
   "sourceType": "industry-report",
   "publisher": "CBRE Switzerland (via europesays.com)",
   "date": "2026-07-05",
   "excerpt": "La capacité actuellement disponible sur le marché suisse des datacenters, hors infrastructures exploitées pour compte propre, s’élève à 340 MW — colocation figures explicitly exclude self-operated capacity.",
   "url": "https://www.europesays.com/ch-fr/205273/",
   "attached": true
  },
  {
   "title": "Switzerland Data Center Market Size & Growth to 2031",
   "sourceType": "analyst-estimate",
   "publisher": "Mordor Intelligence",
   "date": "2023-05-18",
   "excerpt": "Base Year Market Size (2025) | 850.60 megawatt — installed base far exceeds the ~274 MW Statista colocation figure for Switzerland.",
   "url": "https://www.mordorintelligence.com/industry-reports/switzerland-data-center-market",
   "attached": true
  }
 ]
}

THE LEDGER FACTS IT TARGETS (current values, derivations, bands):
[
 {
  "id": "geo.NL",
  "label": "Netherlands",
  "kind": "estimated",
  "value": 0.28,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "triangulated",
  "dimension": "geography",
  "dimensionValue": "NL",
  "sensitivityRange": {
   "low": 0.24,
   "high": 0.31
  },
  "funnelActive": true,
  "derivation": {
   "method": "Top-down capacity apportionment",
   "expression": "NL colo 951 MW ÷ CE-7 colo 3,451 MW (Statista 2025) = 0.276 → 0.28 (normalized)",
   "crossCheck": "Dutch Data Center Association: national colo 924 MW (2024) — consistent scale"
  },
  "provenance": {
   "rationale": "Statista and the national association agree within ~3% → inferred, triangulated."
  },
  "evidence": [
   {
    "title": "Europe colocation data center IT power supply by country, 2024–2031",
    "sourceType": "industry-report",
    "publisher": "Statista",
    "date": "2026-02-06",
    "excerpt": "Netherlands 951 MW of colocation and scale-colocation IT power in 2025.",
    "attached": true
   },
   {
    "title": "Ten years of State of the Dutch Data Centers",
    "sourceType": "industry-report",
    "publisher": "Dutch Data Center Association",
    "date": "2024",
    "excerpt": "In 2024, the total colocation capacity reached 924 megawatts... the Amsterdam Metropolitan Area still accounts for approximately 70% of colocation capacity.",
    "attached": true
   }
  ]
 },
 {
  "id": "geo.CH",
  "label": "Switzerland",
  "kind": "estimated",
  "value": 0.08,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "single-source",
  "dimension": "geography",
  "dimensionValue": "CH",
  "sensitivityRange": {
   "low": 0.07,
   "high": 0.13
  },
  "funnelActive": true,
  "derivation": {
   "method": "Top-down capacity apportionment",
   "expression": "CH colo 274 MW ÷ CE-7 colo 3,451 MW (Statista 2025) = 0.079 → 0.08 (normalized)",
   "crossCheck": "Installed-base method (Mordor 850.6 MW incl. self-operated) → ~0.13 — Swiss market is self-operation-heavy"
  },
  "provenance": {
   "rationale": "Large self-operated share (CBRE Suisse: 340 MW commercial only) makes scope choice decisive → inferred, wide band."
  },
  "evidence": [
   {
    "title": "Europe colocation data center IT power supply by country, 2024–2031",
    "sourceType": "industry-report",
    "publisher": "Statista",
    "date": "2026-02-06",
    "excerpt": "Switzerland 274 MW of colocation and scale-colocation IT power in 2025.",
    "attached": true
   },
   {
    "title": "CBRE Suisse — Swiss data-center market capacity",
    "sourceType": "analyst-estimate",
    "publisher": "CBRE Suisse",
    "date": "2026",
    "excerpt": "Commercial capacity (excluding self-operated infrastructure) is 340 MW across 121 sites; ~61% (209 MW) concentrated in the Zurich region.",
    "attached": true
   }
  ]
 }
]

Emit JSON: { resolution: "error"|"risk", settleTest, proposedCorrection: {nodeId, value, low, high, rationale} or null, researchQueries: [{query, kind}] ([] for risks) }
